const uart=@import("../console/uart.zig"); const vm=@import("vm.zig"); const vcpu=@import("vcpu.zig"); const gef=@import("guest_entry_frame.zig"); const plan=@import("stage2_activation_plan.zig"); const hext=@import("h_extension.zig");
pub const State=enum{empty,built,validated,rejected}; pub const Blocker=enum{none,empty,not_built,entry_frame_missing,csr_safety_missing,h_extension_missing,activation_plan_missing,sepc_corrupt,status_corrupt,active_stage2_forbidden,hgatp_written_forbidden,trap_return_executed_forbidden,guest_entered_forbidden,instruction_executed_forbidden,checksum_zero}; pub const Result=enum{ok,rejected};
pub const TrapReturnFrame=struct{owner_vm_id:vm.VmId,owner_vcpu_id:vcpu.VcpuId,state:State,sepc_candidate:usize,sstatus_candidate:usize,status_bit_metadata:usize,privilege_target_metadata:usize,trap_return_kind_metadata:usize,trap_vector_metadata:usize,entry_frame_checksum:usize,activation_plan_checksum:usize,csr_safety_checksum:usize,h_extension_summary:usize,first_blocker:Blocker,blocker_count:usize,checksum:usize,build_count:usize,validate_count:usize,reject_count:usize,reset_count:usize,trap_return_executed:bool,guest_entered:bool,guest_instruction_executed:bool,hgatp_written:bool,active_stage2:bool};
var obj:TrapReturnFrame=undefined; var inited=false; pub fn init(o:vm.VmId,v:vcpu.VcpuId)void{obj=empty(o,v,0);inited=true;} pub fn object()*const TrapReturnFrame{return mut();} fn mut()*TrapReturnFrame{if(!inited)init(vm.object().id,vcpu.object().id);return &obj;} fn empty(o:vm.VmId,v:vcpu.VcpuId,r:usize)TrapReturnFrame{return .{.owner_vm_id=o,.owner_vcpu_id=v,.state=.empty,.sepc_candidate=0,.sstatus_candidate=0,.status_bit_metadata=0,.privilege_target_metadata=0,.trap_return_kind_metadata=0,.trap_vector_metadata=0,.entry_frame_checksum=0,.activation_plan_checksum=0,.csr_safety_checksum=0,.h_extension_summary=0,.first_blocker=.empty,.blocker_count=1,.checksum=0,.build_count=0,.validate_count=0,.reject_count=0,.reset_count=r,.trap_return_executed=false,.guest_entered=false,.guest_instruction_executed=false,.hgatp_written=false,.active_stage2=false};} pub fn reset()void{const t=mut();obj=empty(t.owner_vm_id,t.owner_vcpu_id,t.reset_count+1);}
fn mix(a:usize,b:usize)usize{return (a ^% (b+%0x94d049bb133111eb))*%0x9e3779b97f4a7c15;} fn calc(t:TrapReturnFrame)usize{var x:usize=0x7472663236; inline for(.{t.owner_vm_id,t.owner_vcpu_id,t.sepc_candidate,t.sstatus_candidate,t.status_bit_metadata,t.privilege_target_metadata,t.trap_return_kind_metadata,t.trap_vector_metadata,t.entry_frame_checksum,t.activation_plan_checksum,t.csr_safety_checksum,t.h_extension_summary})|v| x=mix(x,v); return if(x==0)1 else x;} fn csrSum()usize{const h=hext.object(); var x:usize=0x637372; x=mix(x,@intFromEnum(h.state)); x=mix(x,@intFromBool(h.unsafe_csr_read_forbidden)); x=mix(x,h.blocked_csr_count); return if(x==0)1 else x;}
fn ensure()void{if(hext.object().state==.empty){_=hext.discoverSafe();_=hext.validate();} if(gef.object().state!=.validated)_=gef.build(); if(plan.object().state!=.validated){_=plan.build();_=plan.validate();}}
pub fn build()Result{ensure(); const t=mut(); t.build_count+=1;t.state=.built;t.owner_vm_id=vm.object().id;t.owner_vcpu_id=vcpu.object().id; const g=gef.object(); const h=hext.object(); const p=plan.object(); t.sepc_candidate=g.guest_pc;t.sstatus_candidate=g.status_metadata | 0x20;t.status_bit_metadata=g.status_metadata;t.privilege_target_metadata=g.privilege_metadata;t.trap_return_kind_metadata=0x5357524554;t.trap_vector_metadata=g.trap_vector_metadata;t.entry_frame_checksum=g.checksum;t.activation_plan_checksum=p.checksum;t.csr_safety_checksum=csrSum();t.h_extension_summary=mix(@intFromEnum(h.state),h.blocked_csr_count);t.checksum=calc(t.*); return validate();}
fn reject(e:Blocker)Result{const t=mut();t.reject_count+=1;t.state=.rejected;t.first_blocker=e;t.blocker_count=1;return .rejected;} fn first()Blocker{const t=object(); if(t.state==.empty)return .empty; if(gef.object().state!=.validated or t.entry_frame_checksum==0)return .entry_frame_missing; if(!hext.object().unsafe_csr_read_forbidden)return .csr_safety_missing; if(hext.object().state==.empty)return .h_extension_missing; if(plan.object().state!=.validated or t.activation_plan_checksum==0)return .activation_plan_missing; if(t.active_stage2)return .active_stage2_forbidden; if(t.hgatp_written)return .hgatp_written_forbidden; if(t.trap_return_executed)return .trap_return_executed_forbidden; if(t.guest_entered)return .guest_entered_forbidden; if(t.guest_instruction_executed)return .instruction_executed_forbidden; if(t.sepc_candidate!=gef.object().guest_pc)return .sepc_corrupt; if(t.sstatus_candidate!=(t.status_bit_metadata|0x20))return .status_corrupt; if(t.checksum==0)return .checksum_zero; return .none;} pub fn validate()Result{const t=mut();t.validate_count+=1;const e=first();if(e!=.none)return reject(e);t.state=.validated;t.first_blocker=.none;t.blocker_count=0;return .ok;}
pub fn corruptSepc()Result{_=build();mut().sepc_candidate +%= 2;return validate();} pub fn corruptStatus()Result{_=build();mut().sstatus_candidate=0;return validate();} pub fn missingEntry()Result{reset();return reject(.entry_frame_missing);} pub fn missingCsr()Result{_=build();mut().csr_safety_checksum=0; return reject(.csr_safety_missing);} pub fn missingHext()Result{reset();return reject(.h_extension_missing);} pub fn markExecuted()Result{_=build();mut().trap_return_executed = true;return validate();} pub fn markGuest()Result{_=build();mut().guest_entered = true;return validate();} pub fn markInstruction()Result{_=build();mut().guest_instruction_executed = true;return validate();} pub fn markHgatp()Result{_=build();mut().hgatp_written = true;return validate();} pub fn markStage2()Result{_=build();mut().active_stage2 = true;return validate();}
fn bn(e:Blocker)[]const u8{return switch(e){.none=>"none",.empty=>"empty",.not_built=>"not-built",.entry_frame_missing=>"entry-frame-missing",.csr_safety_missing=>"csr-safety-missing",.h_extension_missing=>"h-extension-missing",.activation_plan_missing=>"activation-plan-missing",.sepc_corrupt=>"sepc-corrupt",.status_corrupt=>"status-corrupt",.active_stage2_forbidden=>"active-stage2-forbidden",.hgatp_written_forbidden=>"hgatp-written-forbidden",.trap_return_executed_forbidden=>"trap-return-executed-forbidden",.guest_entered_forbidden=>"guest-entered-forbidden",.instruction_executed_forbidden=>"instruction-executed-forbidden",.checksum_zero=>"checksum-zero"};} fn rn(r:Result)[]const u8{return if(r==.ok)"ok" else "rejected";} fn non()void{uart.write("hv: trap_return_executed=false\r\nhv: guest_entered=false\r\nhv: guest_instruction_executed=false\r\nhv: hgatp_written=false\r\nhv: active_stage2=false\r\n");}
fn summary()void{const t=object();uart.write("hv: trap_return_frame.state=");uart.write(@tagName(t.state));uart.write("\r\nhv: trap_return_frame.sepc_candidate=");uart.writeHex(t.sepc_candidate);uart.write("\r\nhv: trap_return_frame.sstatus_candidate=");uart.writeHex(t.sstatus_candidate);uart.write("\r\nhv: trap_return_frame.entry_frame_checksum=");uart.writeHex(t.entry_frame_checksum);uart.write("\r\nhv: trap_return_frame.activation_plan_checksum=");uart.writeHex(t.activation_plan_checksum);uart.write("\r\nhv: trap_return_frame.csr_safety_checksum=");uart.writeHex(t.csr_safety_checksum);uart.write("\r\nhv: trap_return_frame.checksum=");uart.writeHex(t.checksum);uart.write("\r\nhv: trap_return_frame.build_count=");uart.writeDec(t.build_count);uart.write("\r\nhv: trap_return_frame.validate_count=");uart.writeDec(t.validate_count);uart.write("\r\nhv: trap_return_frame.reject_count=");uart.writeDec(t.reject_count);uart.write("\r\n");}
pub fn printStatusCommand()void{summary();printBlockersCommand();non();} pub fn printBuildCommand()void{const r=build();uart.write("hv: trap_return_frame.build_result=");uart.write(rn(r));uart.write("\r\n");summary();non();} pub fn printValidateCommand()void{const r=validate();uart.write("hv: trap_return_frame.validate_result=");uart.write(rn(r));uart.write("\r\n");summary();printBlockersCommand();non();} pub fn printBlockersCommand()void{uart.write("hv: trap_return_frame.blocker_count=");uart.writeDec(object().blocker_count);uart.write("\r\nhv: trap_return_frame.blocker=");uart.write(bn(object().first_blocker));uart.write("\r\n");} pub fn printFieldsCommand()void{summary();non();} pub fn printChecksumCommand()void{uart.write("hv: trap_return_frame.checksum=");uart.writeHex(object().checksum);uart.write("\r\n");} pub fn printResetCommand()void{reset();uart.write("hv: trap_return_frame.reset_result=ok\r\n");summary();non();} pub fn printTest(label:[]const u8,r:Result)void{uart.write("hv: trap_return_frame.");uart.write(label);uart.write("=");uart.write(rn(r));uart.write("\r\n");printBlockersCommand();summary();non();}
